class Union_Find {

    vector<int> par;

    vector<int> rankmy;

    vector<int> ookisa;



public:

    Union_Find(int size) {

        par = vector<int>(size);

        rankmy = vector<int>(size);

        ookisa=vector<int>(size);

        for (int i = 0; i < size; i++) {

            par[i] = i;

            ookisa[i]=1;

        }

    }



    int find(int x) {

        if (par[x] == x) {

            return x;

        }

        return par[x] = find(par[x]);

    }



    void unite(int x, int y) {

        x = find(x);

        y = find(y);

        if (x == y) {

            return;

        }

        if (rankmy[x] < rankmy[y]) {

            par[x] = y;

            ookisa[y]+=ookisa[x];

            ookisa[x]=0;

        }

        else {

            par[y] = x;

            ookisa[x]+=ookisa[y];

            ookisa[y]=0;

            if (rankmy[x] == rankmy[y]) {

                rankmy[x]++;

            }

        }

    }

    int size(int i){

        i=find(i);

        return ookisa[i];

    }

    bool same(int x, int y){

        return find(x) == find(y);

    }



};



class BIT {

    vector<int> data;

    int size=0;

public:

    BIT(int _size){

        data=vector<int>(_size+1);

        size=_size;

    }

    void add(int i,int x){

        while (i<=size) {

            data[i]+=x;

            i += i & -i;

        }

    }

    int sum(int i){

        assert(i<=size);

        int s=0;

        while(i>0){

            s+=data[i];

            i -= i & -i;

        }

        return s;

    }

    int lower_bound(int x){

        if(x<=0){

            return 0;

        }else{

            int i=0;int r=1;

            while(r<size) r=r<<1;

            for(int len=r;len>0;len=len>>1) {

                if(i+len<size && data[i+len]<x){

                    x-=data[i+len];

                    i+=len;

                }

            }

            return i+1;

        }

    }

};



