    ki=1000000007ll;

    hamod=(one<<61)-1;

    kim=1;

    rep(i,t.size()){

        hikaku*=ki;

        h*=ki;

        kim*=ki;

        hikaku+=t[i];

        h+=s[i];

        hikaku%=hamod;

        h%=hamod;

        kim%=hamod;

