#include <bits/stdc++.h>

using namespace std;



template<typename T>

vector<T> dijkstra(const vector<vector<pair<int, T>>> &g, int s, T inf, T zero

    /* vector<int> prev */) {

  using PTI = pair<T, int>;

  int n = g.size();

  vector<T> d(n, inf);

  priority_queue<PTI, vector<PTI>, greater<PTI>> Q;

  d[s] = zero; Q.push({d[s], s});

  while (!Q.empty()) {

    int p = Q.top().second; Q.pop();

    for (const auto &f : g[p]) {

      int to = f.first; T cost = f.second;

      if (d[to] > d[p] + cost) {

        d[to] = d[p] + cost;

        /* prev[to] = p; */

        Q.push({d[to], to});

      }

    }

  }

  return d;

}



using ll = int64_t;



#define rep(i,n) for (int i = 0; i < n; ++i)



int main() {

  ll n, m, s, t; cin >> n >> m >> s >> t;

  s--, t--;

  vector<vector<pair<int,ll>>> g(n), h(n);

  ll a, b, u, v;

  rep(i,m) {

    cin >> u >> v >> a >> b;

    u--, v--;

    g[u].push_back({v, a});

    g[v].push_back({u, a});

    h[u].push_back({v, b});

    h[v].push_back({u, b});

  }



  vector<ll> dg, dh;

  dg = dijkstra(g, s, (1L << 60), 0L);

  dh = dijkstra(h, t, (1L << 60), 0L);

  vector<ll> ans(n);

  ans[n-1] = dg[n-1] + dh[n-1];

  for (int i = n-1; i > 0; --i) {

    ans[i-1] = min(ans[i], dg[i-1] + dh[i-1]);

  }

  rep(i,n) {

    cout << 1000000000000000L - ans[i] << endl;

  }

  return 0;

}

