vector<int>  RollingHash(string &s, string& t){

    vector<int> ans;

    __int128 h=0,hamod=0,ki=0,kim=0,hikaku=0,one=0;

    one=1;

    ki=1000000007ll;

    hamod=(one<<61)-1;

    kim=1;

    rep(i,t.size()){

        hikaku*=ki;

        h*=ki;

        kim*=ki;

        hikaku+=t[i];

        h+=s[i];

        hikaku%=hamod;

        h%=hamod;

        kim%=hamod;

    }

    rep(i,(int)s.size()-(int)t.size()+1){

        if (h==hikaku) {

            ans.emplace_back(i);

        }

        h*=ki;

        h%=hamod;

        h+=s[i+(int)t.size()];

        h%=hamod;

        h+=hamod;

        h-=s[i]*kim%hamod;

        h%=hamod;

    }

    return ans;

}

struct edge {

    int to;

    int length;

    edge(int _to, int _length){

        to=_to;

        length=_length;

    }

};

vector<int> djkstra(vector<vector<edge>> &road,int start){

    vector<int> kyo(road.size(),inf);

    smallpriority_queue(P) q;

    q.push({0,start});

    kyo[start]=0;

    while (q.size()) {

        int x=q.top().second;

        itn now=q.top().first;

        q.pop();

        if (kyo[x]<now) {

            continue;

        }

        for(auto&i:road[x]){

            if (kyo[i.to]>now+i.length) {

                kyo[i.to]=now+i.length;

                q.push({kyo[i.to],i.to});

            }

        }

    }

    return kyo;

}



